import{_ as t,o,c as a,a5 as r}from"./chunks/framework.JW9VOlAI.js";const u=JSON.parse('{"title":"Platform Mesh Metadata","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/pm-annotations.md","filePath":"concepts/pm-annotations.md"}'),n={name:"concepts/pm-annotations.md"};function s(i,e,d,c,l,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="platform-mesh-metadata" tabindex="-1">Platform Mesh Metadata <a class="header-anchor" href="#platform-mesh-metadata" aria-label="Permalink to &quot;Platform Mesh Metadata&quot;">​</a></h1><p>Platform Mesh uses a small set of API groups, labels, and finalizers to identify the objects it manages and to wire them into the rest of the stack. This page is a reference for that metadata so that when you see a label like <code>core.platform-mesh.io/org</code> or a finalizer like <code>account.core.platform-mesh.io/finalizer</code> in a YAML file, you know what owns it and what to expect.</p><div class="tip custom-block"><p class="custom-block-title">Annotations vs labels vs API groups</p><p>&quot;Platform Mesh annotations&quot; is a loose phrase. In practice, PM uses a few different mechanisms:</p><ul><li><strong>API groups</strong> identify the CRDs PM defines (<code>core.platform-mesh.io</code>, <code>ui.platform-mesh.io</code>).</li><li><strong>Labels</strong> wire PM resources into the Portal, the marketplace, and identity scoping.</li><li><strong>Finalizers</strong> ensure the right cleanup order when objects are deleted.</li><li>True <strong>annotations</strong> are used sparingly — most PM-specific information is in dedicated CRD fields rather than annotations on existing kcp/Kubernetes objects.</li></ul></div><h2 id="api-groups" tabindex="-1">API Groups <a class="header-anchor" href="#api-groups" aria-label="Permalink to &quot;API Groups&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Group</th><th>Owner</th><th>Resources</th></tr></thead><tbody><tr><td><code>core.platform-mesh.io/v1alpha1</code></td><td>account-operator, IAM service</td><td><code>Account</code>, <code>AccountExtension</code>, <code>Store</code></td></tr><tr><td><code>ui.platform-mesh.io/v1alpha1</code></td><td>Extension Manager Operator</td><td><code>ContentConfiguration</code>, <code>ExtensionClass</code> (Portal extensions)</td></tr></tbody></table><p>API resources outside these groups are either upstream kcp (<code>apis.kcp.io</code>, <code>tenancy.kcp.io</code>, etc.), upstream Kubernetes, or provider-specific.</p><h2 id="labels" tabindex="-1">Labels <a class="header-anchor" href="#labels" aria-label="Permalink to &quot;Labels&quot;">​</a></h2><p>Platform Mesh attaches labels to its own resources and, in some cases, to upstream resources it manages. Common ones:</p><table tabindex="0"><thead><tr><th>Label</th><th>Used on</th><th>Purpose</th></tr></thead><tbody><tr><td><code>core.platform-mesh.io/org</code></td><td>WorkspaceTypes managed by the account-operator</td><td>Scopes a workspace type to a specific organization so child accounts inherit the right RBAC.</td></tr><tr><td><code>ui.platform-mesh.io/entity</code></td><td>ContentConfiguration</td><td>Attaches the configuration to a Portal navigation entity (e.g., <code>core_platform-mesh_io_account</code> to extend Account pages).</td></tr><tr><td><code>extensions.openmfp.io</code></td><td>ContentConfiguration (legacy)</td><td>Maps to an ExtensionClass in older deployments. New deployments prefer <code>ui.platform-mesh.io/entity</code>.</td></tr></tbody></table><p>When you write your own provider, you generally do <strong>not</strong> need to set PM labels on your APIExports or APIBindings — the platform owner&#39;s onboarding scripts and the operators handle this for you.</p><h2 id="finalizers" tabindex="-1">Finalizers <a class="header-anchor" href="#finalizers" aria-label="Permalink to &quot;Finalizers&quot;">​</a></h2><p>Finalizers ensure that PM resources are torn down in the right order — for example, an Account&#39;s IAM Store must be cleaned up before the workspace itself is deleted, or stranded permissions remain in OpenFGA.</p><table tabindex="0"><thead><tr><th>Finalizer</th><th>Set by</th><th>Triggers</th></tr></thead><tbody><tr><td><code>account.core.platform-mesh.io/finalizer</code></td><td>account-operator</td><td>Holds the Account until its workspace is deleted.</td></tr><tr><td><code>account.core.platform-mesh.io/info</code></td><td>account-operator</td><td>Holds the Account until its account-info status fields are reconciled to children.</td></tr><tr><td><code>workspacetype.core.platform-mesh.io/finalizer</code></td><td>account-operator (workspacetype subroutine)</td><td>Holds the WorkspaceType created for an org until all child workspaces are gone.</td></tr><tr><td><code>platform-mesh.core.platform-mesh.io/finalizer</code></td><td>platform-mesh-operator</td><td>Coordinates teardown of platform-level provider secrets and kcp setup state.</td></tr></tbody></table><p>You should not normally remove these finalizers by hand. If a resource is stuck on a finalizer, check the operator logs to see which subroutine is blocked rather than force-deleting.</p><h2 id="annotations" tabindex="-1">Annotations <a class="header-anchor" href="#annotations" aria-label="Permalink to &quot;Annotations&quot;">​</a></h2><p>Pure annotations on PM-managed objects are sparse. The codebase uses Kubebuilder-generated annotations (<code>controller-gen.kubebuilder.io/version</code>) on CRDs and standard Kubernetes annotations (e.g., <code>service.binding/*</code> from the <a href="https://servicebinding.io/" target="_blank" rel="noreferrer">Service Binding spec</a> on operator-managed objects), but PM does not impose a custom annotation scheme on top of them today.</p><p>If you encounter a PM annotation in a real cluster that is not documented here, it is likely operator-internal state that is safe to ignore from a user perspective.</p><h2 id="where-this-appears" tabindex="-1">Where This Appears <a class="header-anchor" href="#where-this-appears" aria-label="Permalink to &quot;Where This Appears&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-80/concepts/account-cr.html"><strong>Account CR</strong></a> — uses the <code>core.platform-mesh.io</code> API group and its finalizers</li><li><a href="/pr-preview/pr-80/concepts/content-configuration.html"><strong>ContentConfiguration</strong></a> — uses the <code>ui.platform-mesh.io</code> API group and the <code>ui.platform-mesh.io/entity</code> label</li><li><a href="/pr-preview/pr-80/concepts/iam-store.html"><strong>IAM Store</strong></a> — uses the <code>core.platform-mesh.io</code> API group</li><li><a href="/pr-preview/pr-80/concepts/api-export-binding.html"><strong>APIExport &amp; APIBinding</strong></a> — vanilla kcp objects; PM does not require additional labels on these by default, though provider onboarding may add them</li></ul><h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-80/concepts/account-cr.html"><strong>Account CR</strong></a> — see PM API groups and finalizers in a concrete object</li><li><a href="/pr-preview/pr-80/concepts/content-configuration.html"><strong>ContentConfiguration</strong></a> — see the <code>ui.platform-mesh.io/entity</code> label in use</li><li><a href="/pr-preview/pr-80/overview/architecture.html"><strong>Architecture</strong></a> — see how the operators that own this metadata fit together</li></ul>',21)])])}const m=t(n,[["render",s]]);export{u as __pageData,m as default};
